questionText:
Qu’affiche ce code ?
&lt;pre&gt;&lt;code&gt;
struct S { public int X; }
class C { public int X; }

var s1 = new S { X = 5 };
var s2 = s1;
s2.X = 10;

var c1 = new C { X = 5 };
var c2 = c1;
c2.X = 10;

Console.WriteLine($"{s1.X} - {c1.X}");
&lt;/code&gt;&lt;/pre&gt;

Quelle est la sortie de ce code utilisant un &lt;code&gt;record struct&lt;/code&gt; ?
&lt;pre&gt;&lt;code&gt;
record struct Point(int X, int Y);

var p1 = new Point(3, 4);
var p2 = p1 with { X = 5 };
Console.WriteLine($"{p1.X},{p1.Y} - {p2.X},{p2.Y}");
&lt;/code&gt;&lt;/pre&gt;
